# GERENCIADOR DE CONFIGURAÇÕES
# ═══════════════════════════════════════════════════════════════════════════════

class ConfigManager:
    """Gerencia configurações do sistema armazenadas em arquivo JSON."""
    
    def __init__(self, config_file='config.json'):
        self.config_file = resource_path(config_file)
        self.config = self._load_config()
    
    def _load_config(self) -> dict:
        """Carrega configurações do arquivo JSON."""
        default_config = {
            'pipefy': {
                'client_id': 'ofgUSnXFhXadEzrDd_ZtUzXsV8-Crv-0NFboRn0CbrU',
                'client_secret': 'DyLPVER8t6SIeVpO7lQiDqTzoquM3UqLDOUgOFtHFpw',
                'token_url': 'https://app.pipefy.com/oauth/token',
                'api_url': 'https://api.pipefy.com/graphql'
            }
        }
        
        if os.path.exists(self.config_file):
            try:
                with open(self.config_file, 'r', encoding='utf-8') as f:
                    loaded_config = json.load(f)
                    # Mesclar com default para garantir todas as chaves
                    default_config.update(loaded_config)
                    return default_config
            except Exception as e:
                print(f"Erro ao carregar configurações: {e}")
                return default_config
        else:
            # Criar arquivo de configuração padrão
            self._save_config(default_config)
            return default_config
    
    def _save_config(self, config: dict = None):
        """Salva configurações no arquivo JSON."""
        if config is None:
            config = self.config
        
        try:
            with open(self.config_file, 'w', encoding='utf-8') as f:
                json.dump(config, f, indent=4, ensure_ascii=False)
            return True
        except Exception as e:
            print(f"Erro ao salvar configurações: {e}")
            return False
    
    def get_pipefy_credentials(self) -> dict:
        """Retorna credenciais do Pipefy."""
        return self.config.get('pipefy', {})
    
    def update_pipefy_credentials(self, client_id: str, client_secret: str) -> bool:
        """Atualiza credenciais do Pipefy."""
        if 'pipefy' not in self.config:
            self.config['pipefy'] = {}
        
        self.config['pipefy']['client_id'] = client_id
        self.config['pipefy']['client_secret'] = client_secret
        return self._save_config()
    
    def get(self, key: str, default=None):
        """Obtém valor de configuração por chave."""
        return self.config.get(key, default)
    
    def set(self, key: str, value) -> bool:
        """Define valor de configuração por chave."""
        self.config[key] = value
        return self._save_config()


# Instância global do gerenciador de configurações
config_manager = ConfigManager()


