    def center_on_screen(self):
        """Centraliza o diálogo na tela."""
        screen = QApplication.primaryScreen().geometry()
        x = (screen.width() - self.width()) // 2
        y = (screen.height() - self.height()) // 2
        self.move(x, y)
    
    def toggle_secret_visibility(self):
        """Alterna visibilidade do Client Secret."""
        if self.client_secret_input.echoMode() == QLineEdit.Password:
            self.client_secret_input.setEchoMode(QLineEdit.Normal)
            self.toggle_secret_btn.setText("🙈")
        else:
            self.client_secret_input.setEchoMode(QLineEdit.Password)
            self.toggle_secret_btn.setText("👁")
    
    def test_connection(self):
        """Testa conexão com Pipefy usando as credenciais informadas."""
        client_id = self.client_id_input.text().strip()
        client_secret = self.client_secret_input.text().strip()
        
        if not client_id or not client_secret:
            self.status_label.setText("❌ Preencha todas as credenciais")
            self.status_label.setStyleSheet("QLabel { color: #dc2626; font-weight: bold; }")
            return
        
        self.status_label.setText("⏳ Testando conexão...")
        self.status_label.setStyleSheet("QLabel { color: #f59e0b; font-weight: bold; }")
        QApplication.processEvents()
        
        try:
            client = PipefyClient(client_id, client_secret, PIPEFY_TOKEN_URL)
            client.authenticate()
            self.status_label.setText("✅ Conexão bem-sucedida!")
            self.status_label.setStyleSheet("QLabel { color: #10b981; font-weight: bold; }")
        except Exception as e:
            self.status_label.setText(f"❌ Erro: {str(e)[:50]}")
            self.status_label.setStyleSheet("QLabel { color: #dc2626; font-weight: bold; }")
    
    def save_settings(self):
        """Salva as configurações."""
        client_id = self.client_id_input.text().strip()
        client_secret = self.client_secret_input.text().strip()
        
        if not client_id or not client_secret:
            self.status_label.setText("❌ Preencha todas as credenciais")
            self.status_label.setStyleSheet("QLabel { color: #dc2626; font-weight: bold; }")
            return
        
        if config_manager.update_pipefy_credentials(client_id, client_secret):
            self.status_label.setText("✅ Configurações salvas! Reinicie o sistema.")
            self.status_label.setStyleSheet("QLabel { color: #10b981; font-weight: bold; }")
            QTimer.singleShot(1500, self.accept)
        else:
            self.status_label.setText("❌ Erro ao salvar configurações")
            self.status_label.setStyleSheet("QLabel { color: #dc2626; font-weight: bold; }")


