class LoadingWorker(QThread):
    """Thread para executar carregamento em background."""
    progress = pyqtSignal(int, str)  # progresso, mensagem
    finished = pyqtSignal(dict)  # dados carregados
    error = pyqtSignal(str)
    
    def __init__(self, parent=None):
        super().__init__(parent)
        self.data = {}
        
    def run(self):
        """Executa o carregamento real dos dados do sistema."""
        try:
            # Etapa 1: Importar bibliotecas pesadas
            self.progress.emit(5, "Carregando bibliotecas...")
            _import_heavy_libraries()
            self.data['initialized'] = True

            # Etapa 2: Verificar conexão com rede
            self.progress.emit(20, "Verificando conexão com rede...")
            base_relatorios = r"G:\SUPRIMENTOS\SUPRIMENTOS\PROJETOS\Relatórios"
            rede_ok = os.path.exists(base_relatorios)
            self.data['rede_disponivel'] = rede_ok
            if rede_ok:
                self.progress.emit(30, "Rede disponível ✓")
            else:
                self.progress.emit(30, "Rede indisponível — modo offline")

            # Etapa 3: Detectar arquivos disponíveis
            self.progress.emit(40, "Localizando relatórios...")
            if rede_ok:
                from dateutil.relativedelta import relativedelta
                meses = {1:'janeiro',2:'fevereiro',3:'marco',4:'abril',5:'maio',
                         6:'junho',7:'julho',8:'agosto',9:'setembro',10:'outubro',
                         11:'novembro',12:'dezembro'}
                mes_ant = datetime.now() - relativedelta(months=1)
                mes_nome = meses[mes_ant.month]
                ano_str = str(mes_ant.year)
                tipos_pasta = ['Estoque periodico', 'Geral contabil']
                arquivos_encontrados = 0
                for tipo in tipos_pasta:
                    pasta = os.path.join(base_relatorios, tipo, ano_str, mes_nome)
                    if os.path.exists(pasta):
                        for f in os.listdir(pasta):
                            if f.lower().endswith(('.xlsx', '.xls')):
                                arquivos_encontrados += 1
                self.data['arquivos_encontrados'] = arquivos_encontrados
                self.progress.emit(60, f"{arquivos_encontrados} arquivos localizados")
            else:
                self.progress.emit(60, "Prosseguindo sem arquivos de rede...")

            # Etapa 4: Verificar configurações
            self.progress.emit(70, "Carregando configurações...")
            config_path = resource_path('estoque_minimo_config.json')
            self.data['config_existe'] = os.path.exists(config_path)

            # Etapa 5: Preparar módulos
            self.progress.emit(85, "Preparando módulos do sistema...")

            # Etapa 6: Finalizar
            self.progress.emit(95, "Finalizando carregamento...")
            self.data['ready'] = True

            self.progress.emit(100, "✓ Pronto!")
            self.finished.emit(self.data)
            
        except Exception as e:
            self.error.emit(f"Erro durante carregamento: {str(e)}")


class SectionLoadWorker(QThread):
    """Thread genérica para carregar dados de uma seção com progresso."""
    progress = pyqtSignal(int, str)  # porcentagem, mensagem
    finished = pyqtSignal()
    error = pyqtSignal(str)

    def __init__(self, steps, parent=None):
        """steps: lista de tuplas (percent, message, callable)"""
        super().__init__(parent)
        self._steps = steps

    def run(self):
        try:
            for i, (pct, msg, fn) in enumerate(self._steps):
                self.progress.emit(pct, msg)
                fn()
                # Pequena pausa entre etapas para a animação JS acompanhar
                QThread.msleep(80)
            self.progress.emit(100, "Concluído!")
            QThread.msleep(300)
            self.finished.emit()
        except Exception as e:
            self.error.emit(str(e))


