class DataHandler:
    """Classe responsável por manipular e processar dados de pagamentos e estoque."""
    
    def __init__(self):
        self.df_pagamentos: Optional[pd.DataFrame] = None
        self.df_estoque: Optional[pd.DataFrame] = None
        self.df_ordens: Optional[pd.DataFrame] = None
        self.df_movimentacoes: Optional[pd.DataFrame] = None
        self.df_ordens_compra: Optional[pd.DataFrame] = None  # Dados reais de ordens de compra
        self.df_distribuicao_conta: Optional[pd.DataFrame] = None  # Distribuição por Conta (movimentações)
        
        # Dados históricos para comparação
        self.df_ordens_compra_2025: Optional[pd.DataFrame] = None  # Dados de 2025 para comparação
        self.df_ordens_compra_2026_todos: Optional[pd.DataFrame] = None  # Todos os meses de 2026
        self.df_pagamentos_2025: Optional[pd.DataFrame] = None  # Pagamentos de 2025
        self._cache_6meses: dict = {}  # Cache de _preparar_df_ultimos_6_meses keyed by (mes_ref, bu)
        self._cache_analise_precos: dict = {}  # Cache do resultado final de get_analise_variacao_precos
        self._cache_perf: dict = {}  # Cache de get_performance_negociacao keyed by (mes_ref, bu)
        self._cache_comp: dict = {}  # Cache de get_comparacao_csc_vs_local keyed by (mes_ref, bu)
        # Diretório de cache local (evita releitura de Excel da rede a cada abertura)
        self._cache_dir = os.path.join(os.path.expanduser('~'), '.gestao_cache')
