        # Flags para controlar se os dados de cada seção já foram carregados
        self._loaded = {
            'estoque': False,
            'pagamentos': False,
            'geral_contabil': False,  # ordens + movimentações
            'historico': False,       # 2025 + 2026 + análise preços
        }
        
        # Configuração do diretório base de relatórios
