    def fmt_currency(val):
        try:
            if val is None or pd.isna(val):
                return "R$ 0,00"
            val_float = float(val)
            return f"R$ {val_float:,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")
        except (ValueError, TypeError):
            return "R$ 0,00"
    
    def fmt_numero(val):
        try:
            if val is None or pd.isna(val):
                return "0"
            return f"{float(val):,.0f}".replace(",", ".")
        except:
            return "0"
    
