    # === GERAR ALERTAS DE ESTOQUE MÍNIMO ===
    alertas_estoque_minimo = ""
    if estoque_minimo_config and df_estoque is not None:
        itens_criticos = []
        itens_abaixo = []
        itens_proximos = []
        
        # Filtrar apenas EMG BETIM
        df_filtrado = df_estoque.copy()
        if 'Nome da Organização' in df_filtrado.columns:
            df_filtrado = df_filtrado[df_filtrado['Nome da Organização'].astype(str).str.contains('EMG BETIM', case=False, na=False)]
        
        # Analisar todos os itens configurados
        for categoria, itens_config in estoque_minimo_config.get('categorias', {}).items():
            for codigo, config in itens_config.items():
                # Buscar item no estoque atual e somar quantidades de subinventários
                try:
                    item_df = df_filtrado[df_filtrado['Nome do Item'].astype(str) == str(codigo)]
                    
                    if not item_df.empty:
                        # Somar quantidades de todos os subinventários
                        qtd_atual = float(item_df['Quantidade'].sum())
                        qtd_minima = config.get('qtd_minima', 0)
                        
                        # Pegar descrição do primeiro registro
                        item = item_df.iloc[0]
                        descricao = str(item.get('Descrição do Item', 'N/A'))
                        
                        item_info = {
                            'codigo': codigo,
                            'descricao': descricao[:50],
                            'qtd_atual': qtd_atual,
                            'qtd_minima': qtd_minima,
                            'categoria': categoria
                        }
                        
                        if qtd_atual <= 0:
                            itens_criticos.append(item_info)
                        elif qtd_atual < qtd_minima:
                            itens_abaixo.append(item_info)
                        elif qtd_atual < qtd_minima * 1.2:
                            itens_proximos.append(item_info)
                except Exception as e:
                    print(f"Erro ao processar item {codigo}: {e}")
                    continue
        
        # Gerar HTML dos alertas somente se houver algo para alertar
        if itens_criticos or itens_abaixo or itens_proximos:
            alertas_html = ""
            
