def _gerar_mapa_brasil_fornecedores(por_uf: dict, geojson_data=None) -> str:
    """Gera mapa coroplético do Brasil com contagem de fornecedores por UF."""
    if not por_uf:
        return "<p style='color:#999;text-align:center;padding:20px;'>Nenhum dado de localização cadastrado</p>"

    # Mapear sigla UF → nome completo conforme GeoJSON do IBGE
    uf_nome = {
        'AC': 'Acre', 'AL': 'Alagoas', 'AP': 'Amapá', 'AM': 'Amazonas',
        'BA': 'Bahia', 'CE': 'Ceará', 'DF': 'Distrito Federal', 'ES': 'Espírito Santo',
        'GO': 'Goiás', 'MA': 'Maranhão', 'MT': 'Mato Grosso', 'MS': 'Mato Grosso do Sul',
        'MG': 'Minas Gerais', 'PA': 'Pará', 'PB': 'Paraíba', 'PR': 'Paraná',
        'PE': 'Pernambuco', 'PI': 'Piauí', 'RJ': 'Rio de Janeiro', 'RN': 'Rio Grande do Norte',
        'RS': 'Rio Grande do Sul', 'RO': 'Rondônia', 'RR': 'Roraima', 'SC': 'Santa Catarina',
        'SP': 'São Paulo', 'SE': 'Sergipe', 'TO': 'Tocantins'
    }
    por_nome = {uf_nome.get(k, k): v for k, v in por_uf.items()}
    max_val = max(por_nome.values(), default=1)

    # Mapa textual simples (tabela por região) quando sem GeoJSON
    regioes = {
        'Norte': ['AC','AM','AP','PA','RO','RR','TO'],
        'Nordeste': ['AL','BA','CE','MA','PB','PE','PI','RN','SE'],
        'Centro-Oeste': ['DF','GO','MS','MT'],
        'Sudeste': ['ES','MG','RJ','SP'],
        'Sul': ['PR','RS','SC'],
    }
    rows = ""
    for regiao, ufs in regioes.items():
        total_regiao = sum(por_uf.get(uf, 0) for uf in ufs)
        ufs_com = [(uf, por_uf.get(uf, 0)) for uf in ufs if por_uf.get(uf, 0) > 0]
        detalhes = ", ".join(f"{uf}:{n}" for uf, n in sorted(ufs_com, key=lambda x: -x[1]))
        rows += f"""
        <tr>
            <td style="padding:8px 12px;font-weight:600;">{regiao}</td>
            <td style="padding:8px 12px;text-align:right;font-weight:700;color:#2d3748;">{total_regiao}</td>
            <td style="padding:8px 12px;font-size:0.82rem;color:#718096;">{detalhes or '—'}</td>
        </tr>
        """

    # Top estados
    top_estados = sorted(por_uf.items(), key=lambda x: -x[1])[:5]
    top_html = ""
    for uf, cnt in top_estados:
        pct = (cnt / sum(por_uf.values()) * 100) if por_uf else 0
        top_html += f"""
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;">
            <span style="background:#2d3748;color:white;padding:4px 10px;border-radius:6px;font-weight:700;font-size:0.85rem;min-width:40px;text-align:center;">{uf}</span>
            <div style="flex:1;background:#e2e8f0;border-radius:6px;height:10px;overflow:hidden;">
                <div style="background:linear-gradient(90deg,#667eea,#764ba2);height:10px;width:{pct:.0f}%;"></div>
            </div>
            <span style="font-weight:700;color:#2d3748;min-width:30px;">{cnt}</span>
        </div>
        """

    return f"""
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;">
        <div>
            <p style="font-size:0.8rem;color:#718096;font-weight:700;text-transform:uppercase;margin-bottom:8px;">Top Estados</p>
            {top_html}
        </div>
        <div>
            <table style="width:100%;border-collapse:collapse;font-size:0.85rem;">
                <thead><tr style="background:#f7fafc;">
                    <th style="padding:6px 8px;text-align:left;">Região</th>
                    <th style="padding:6px 8px;text-align:right;">Total</th>
                    <th style="padding:6px 8px;">Estados</th>
                </tr></thead>
                <tbody>{rows}</tbody>
            </table>
        </div>
    </div>
    """


