    def handle_generate_report(self, report_type: str):
        """Handler para navegação entre páginas."""
        report_map = {
            'dashboard': self.load_estoque,
            'estoque': self.load_estoque,
            'ordens': self.load_ordens,
            'movimentacoes': self.load_movimentacoes,
            'atividades': self.load_atividades,
            'conferencia_nfe': self.load_conferencia_nfe,
            'analise_precos': self.load_analise_precos,
            'carteira_fornecedores': self.load_carteira_fornecedores,
        }
        
        if report_type in report_map:
            report_map[report_type]()
    
    def _setup_file_monitoring(self):
        """Configura monitoramento automático das pastas de relatórios."""
        self.file_watcher = QFileSystemWatcher()
        
        # Obter mês e ano atual
        mes, ano = self.data_handler._get_mes_ano_atual()
        base_path = self.data_handler.base_relatorios
        
        # Pastas a monitorar
        pastas_monitorar = [
            os.path.join(base_path, 'Estoque periodico', ano, mes),
            os.path.join(base_path, 'Geral contabil', ano, mes),
        ]
        
        # Monitorar pasta Geral contabil do ano para detectar novos meses (Análise de Preços)
        pasta_geral_ano = os.path.join(base_path, 'Geral contabil', ano)
        if os.path.exists(pasta_geral_ano):
            pastas_monitorar.append(pasta_geral_ano)
            # Monitorar subpastas de meses já existentes
            for sub in os.listdir(pasta_geral_ano):
                sub_path = os.path.join(pasta_geral_ano, sub)
                if os.path.isdir(sub_path):
                    pastas_monitorar.append(sub_path)
        
        # Adicionar pastas existentes ao watcher
        for pasta in pastas_monitorar:
            if os.path.exists(pasta):
                self.file_watcher.addPath(pasta)
        
        # Conectar sinais
        self.file_watcher.directoryChanged.connect(self._on_directory_changed)
    
    def _on_directory_changed(self, path: str):
        """Callback quando um arquivo é adicionado/modificado na pasta monitorada."""
        print(f"\n🔄 Mudança detectada em: {path}")
        
        # Aguardar 1 segundo para o arquivo ser completamente copiado
        QTimer.singleShot(1000, lambda: self._recarregar_dados(path))
    
    def _recarregar_dados(self, path: str):
        """Recarrega os dados quando arquivos são adicionados."""
        
        # Identificar tipo de relatório pela pasta
        if 'Pagamentos' in path:
            arquivo = self.data_handler._buscar_arquivo_na_pasta(path)
            if arquivo:
                self.data_handler.load_payment_file(arquivo)
                self.data_handler._loaded['pagamentos'] = True
                self._atualizar_view_se_necessario()
        
        elif 'Estoque periodico' in path:
            arquivo = self.data_handler._buscar_arquivo_na_pasta(path)
            if arquivo:
                self.data_handler.load_estoque_file(arquivo)
                self.data_handler._loaded['estoque'] = True
                self._atualizar_view_se_necessario()
        
        elif 'Geral contabil' in path:
            arquivo = self.data_handler._buscar_arquivo_na_pasta(path)
            if arquivo:
                self.data_handler.load_ordens_compra_file(arquivo)
                self.data_handler._loaded['geral_contabil'] = True
            
            # Invalidar cache de dados 2026 para que a Análise de Preços recarregue
            self.data_handler.df_ordens_compra_2026_todos = None
            print("🔄 Cache de dados 2026 invalidado — Análise de Preços será atualizada")
            
            # Se uma nova pasta de mês foi criada, adicionar ao watcher
            if os.path.isdir(path):
                for sub in os.listdir(path):
                    sub_path = os.path.join(path, sub)
                    if os.path.isdir(sub_path) and sub_path not in self.file_watcher.directories():
                        self.file_watcher.addPath(sub_path)
                        print(f"📂 Nova pasta monitorada: {sub_path}")
            
            self._atualizar_view_se_necessario()
    
    def _atualizar_view_se_necessario(self):
        """Atualiza a visualização atual após recarregar dados."""
        
        # Recarregar a view atual
        if self.current_view == "dashboard" or self.current_view == "estoque":
            self.load_estoque()
        elif self.current_view == "ordens":
            self.load_ordens()
        elif self.current_view == "movimentacoes":
            self.load_movimentacoes()
        elif self.current_view == "analise_precos":
            self.load_analise_precos()
        elif self.current_view == "carteira_fornecedores":
            self.load_carteira_fornecedores()
        
        # Mostrar notificação ao usuário
        QTimer.singleShot(500, lambda: QMessageBox.information(
            self, 
            "Dados Atualizados", 
            "Os dados foram atualizados automaticamente com os novos arquivos!",
            QMessageBox.Ok
        ))
    
    def _render_html(self, html_content: str):
        """Renderiza HTML no WebView."""
        try:
            # Ensure html_content is a string
            if not isinstance(html_content, str):
                html_content = str(html_content)
            
            base_html = get_base_html()
            full_html = base_html.replace(
                '<div class="dashboard-container" id="dashboard">\n        <!-- Conteúdo será injetado aqui -->\n    </div>',
                f'<div class="dashboard-container" id="dashboard">\n{html_content}\n    </div>'
            )
            self.web_view.setHtml(full_html)
        except Exception as e:
            print(f"Erro ao renderizar HTML: {e}")
            # Fallback to a simple error message
            error_html = "<div style='padding: 40px; text-align: center; color: red;'><h2>Erro ao carregar conteúdo</h2><p>Verifique os dados e tente novamente.</p></div>"
            self.web_view.setHtml(error_html)
    
    def _update_nav(self, active_key: str):
        """Atualiza botões de navegação."""
        for key, btn in self.nav_buttons.items():
            if key in self._action_keys:
                continue  # Botões de ação não são checkáveis
            btn.setChecked(key == active_key)

