    def _get_servico_subcategorias(self):
        """Retorna lista ordenada de sub-categorias disponíveis no pipe de Serviços."""
        cards = self.pipefy_data.get('compras_servicos', {}).get('cards', [])
        if not cards and self.pipefy_cards:
            cards = self.pipefy_cards
        cats = set()
        for card in cards:
            for field in card.get('fields', []):
                if field.get('name') == 'Categoria - Fornecedor':
                    val = (field.get('value') or '').strip()
                    if val and val != '- Não Aplicável':
                        cats.add(val)
        return sorted(cats)

