                    window.total_synchro_fornecedores = """ + str(total_synchro_fornecedores) + """;
                    window.total_oracle_notas = """ + str(total_oracle_notas) + """;
                    window.notas_em_comum_count = """ + str(notas_em_comum_count) + """;
                    window.notas_nao_enviadas_oracle = """ + str(notas_nao_enviadas_oracle) + """;
                    window.excecoes_cnpj = """ + str(len(clientes_cnpjs)) + """;
