    def _gerar_pdf_analise_precos(self, file_path: str, analise: Dict, progress_dialog=None,
                                   analise_perf: Dict = None, analise_comp: Dict = None,
                                   bu_label: str = None):
        """Gera PDF completo com análise de preços — título, alertas c/ nome do produto,
        gráficos IPCA, tabelas com preço anterior x atual, comparação 2025 vs 2026,
        performance de compradores e CSC vs Compras Locais."""
        analise_perf = analise_perf or {}
        analise_comp = analise_comp or {}
        from datetime import timezone

        # ── helpers ──────────────────────────────────────────────────────
        def fmt_r(v):
            try:
                return f"R$ {float(v):,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")
            except Exception:
                return "R$ 0,00"

        def fmt_p(v, sign=False):
            try:
                s = f"{float(v):.1f}%"
                if sign and float(v) > 0:
                    s = "+" + s
                return s
            except Exception:
                return "0.0%"

        # ── dimensões e logo (mesmo padrão do PDF de Ordens de Compra) ──────────
        _PAGE_W, _PAGE_H = landscape(A4)
        _MARGIN   = 1.5 * cm
        _HEADER_H = 2.4 * cm
        _LOGO_PATH = r"G:\SUPRIMENTOS\SUPRIMENTOS\PROJETOS\img\logo_regional.png"
        _FOOTER_TXT = "Suprimentos Regional MG/GO"
        data_geracao = datetime.now().strftime("%d/%m/%Y às %H:%M")

        def _draw_header_ap(canvas, doc):
            """Faixa escura no topo com logo e título — igual à ordem de compra."""
            canvas.saveState()
            canvas.setFillColor(colors.HexColor('#2d3748'))
            canvas.rect(0, _PAGE_H - _HEADER_H, _PAGE_W, _HEADER_H, fill=1, stroke=0)
            import os as _os
            if _os.path.isfile(_LOGO_PATH):
                try:
                    _lh = _HEADER_H * 0.90
                    _lw = _lh * 4.5
                    canvas.drawImage(_LOGO_PATH, _MARGIN,
                                     _PAGE_H - _HEADER_H + (_HEADER_H - _lh) / 2,
                                     width=_lw, height=_lh,
                                     preserveAspectRatio=True, mask='auto')
                except Exception:
                    pass
            canvas.setFillColor(colors.white)
            _ym = _PAGE_H - _HEADER_H / 2
            canvas.setFont('Helvetica-Bold', 9)
            canvas.drawRightString(_PAGE_W - _MARGIN, _ym + 3, "Relatório Analítico de Preços")
            canvas.setFont('Helvetica', 7.5)
            canvas.setFillColor(colors.HexColor('#a0aec0'))
            canvas.drawRightString(_PAGE_W - _MARGIN, _ym - 7, _FOOTER_TXT)
            canvas.restoreState()

        def _footer_ap(canvas, doc):
            _draw_header_ap(canvas, doc)
            canvas.saveState()
            canvas.setFont('Helvetica', 8)
            canvas.setFillColor(colors.HexColor('#a0aec0'))
            canvas.drawString(_MARGIN, 0.8 * cm, _FOOTER_TXT)
            canvas.drawRightString(_PAGE_W - _MARGIN, 0.8 * cm,
                f"Gerado em {data_geracao}  |  Pág. {doc.page}")
            canvas.restoreState()

        # ── documento ────────────────────────────────────────────────────
        doc = SimpleDocTemplate(
            file_path,
            pagesize=landscape(A4),
            rightMargin=_MARGIN,
            leftMargin=_MARGIN,
            topMargin=_HEADER_H + 0.5*cm,
            bottomMargin=1.8*cm
        )

        styles = getSampleStyleSheet()
        elements = []

        # ── estilos ──────────────────────────────────────────────────────
        title_style = ParagraphStyle('TA_Title', parent=styles['Heading1'],
            fontSize=20, textColor=colors.HexColor('#1a202c'),
            spaceAfter=6, alignment=TA_CENTER, fontName='Helvetica-Bold')

        subtitle_style = ParagraphStyle('TA_Sub', parent=styles['Normal'],
            fontSize=11, textColor=colors.HexColor('#4a5568'),
            spaceAfter=4, alignment=TA_CENTER)

        unit_style = ParagraphStyle('TA_Unit', parent=styles['Normal'],
            fontSize=13, textColor=colors.HexColor('#2d3748'),
            spaceAfter=20, alignment=TA_CENTER, fontName='Helvetica-Bold')

        section_style = ParagraphStyle('TA_Section', parent=styles['Heading2'],
            fontSize=12, textColor=colors.white,
            spaceBefore=16, spaceAfter=10,
            fontName='Helvetica-Bold',
            backColor=colors.HexColor('#2d3748'),
            leftIndent=-4, rightIndent=-4,
            borderPadding=(4, 6, 4, 6))

        normal_style = ParagraphStyle('TA_Normal', parent=styles['Normal'],
            fontSize=8.5, textColor=colors.HexColor('#4a5568'), spaceAfter=4)

        small_style = ParagraphStyle('TA_Small', parent=styles['Normal'],
            fontSize=7.5, textColor=colors.HexColor('#718096'))

        bold_style = ParagraphStyle('TA_Bold', parent=styles['Normal'],
            fontSize=8.5, fontName='Helvetica-Bold',
            textColor=colors.HexColor('#2d3748'))

        center_style = ParagraphStyle('TA_Center', parent=styles['Normal'],
            fontSize=8.5, textColor=colors.HexColor('#4a5568'), spaceAfter=4,
            alignment=TA_CENTER)

        footer_style = ParagraphStyle('TA_Footer', parent=styles['Normal'],
            fontSize=7, textColor=colors.HexColor('#a0aec0'), alignment=TA_CENTER)

        RED   = colors.HexColor('#e53e3e')
        GREEN = colors.HexColor('#38a169')
        BLUE  = colors.HexColor('#3182ce')
        GRAY  = colors.HexColor('#718096')
        DARK  = colors.HexColor('#2d3748')
        LIGHT = colors.HexColor('#f7fafc')

        def hdr(text, bg=DARK):
            return ParagraphStyle(f'H_{text[:6]}', parent=styles['Normal'],
                fontSize=8.5, fontName='Helvetica-Bold',
                textColor=colors.white, alignment=TA_CENTER)

        def tbl_style(header_bg, row_bg1, row_bg2, grid_color):
            return TableStyle([
                ('BACKGROUND', (0,0), (-1,0), header_bg),
                ('TEXTCOLOR', (0,0), (-1,0), colors.white),
                ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),
                ('FONTSIZE', (0,0), (-1,-1), 8),
                ('ALIGN', (0,0), (-1,-1), 'CENTER'),
                ('ALIGN', (2,1), (2,-1), 'LEFT'),
                ('VALIGN', (0,0), (-1,-1), 'MIDDLE'),
                ('ROWBACKGROUNDS', (0,1), (-1,-1), [row_bg1, row_bg2]),
                ('GRID', (0,0), (-1,-1), 0.5, grid_color),
                ('BOTTOMPADDING', (0,0), (-1,-1), 5),
                ('TOPPADDING', (0,0), (-1,-1), 5),
            ])

        def col_p(text, style=normal_style):
            return Paragraph(str(text), style)

