        # Remover itens com variação acima de 80%
        produtos_aumento = [p for p in produtos_aumento if abs(p.get('variacao_percentual', 0)) <= 80]
        produtos_reducao = [p for p in produtos_reducao if abs(p.get('variacao_percentual', 0)) <= 80]

