                ax2.set_xlabel('Variação (%)', fontsize=8)
                ax2.set_title('Top 10 Maiores Aumentos de Preço', fontsize=10, fontweight='bold', color='#2d3748')
                ax2.grid(axis='x', alpha=0.4, zorder=0)
                ax2.spines['top'].set_visible(False)
                ax2.spines['right'].set_visible(False)
