                    col_p(str(row.get('total_pedidos', 0))),
                    col_p(str(row.get('itens_distintos', 0))),
                    col_p(fmt_r(row.get('valor_total', 0))),
                    col_p(fmt_r(row.get('ticket_medio', 0))),
